INSERT INTO blog_posts (id, titulo, contenido, imagen, tipo, autor, empresa_id, usuario_id, publicado, fecha_publicacion, slug, created_at, updated_at) VALUES
(1, 'Festival del Folclor 2026', 'El festival anual de música y danza tradicional tolimense se celebrará en la plaza principal.', NULL, 'noticia', NULL, NULL, NULL, true, '2026-04-22 12:23:50', 'festival-del-folclor-2026-69e8bdd6a0365', '2026-04-22 12:23:50', '2026-04-22 12:23:50'),
(2, 'Nueva ruta ecoturística', 'Se habilitó una nueva ruta de senderismo que conecta tres cascadas del municipio de Ortega.', NULL, 'noticia', NULL, NULL, NULL, true, '2026-04-22 12:23:00', 'nueva-ruta-ecoturistica-69e8bdd6a6d28', '2026-04-22 12:23:50', '2026-04-22 12:23:50'),
(3, 'Descubre Ortega: El Tesoro Escondido del Tolima', 'Ortega es un municipio del Tolima que guarda paisajes naturales únicos, cultura indígena Pijao y una gastronomía auténtica que enamora a todo viajero. En este artículo te contamos por qué debe ser tu próximo destino.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'descubre-ortega-el-tesoro-escondido-del-tolima-69f0065e0aacc', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(4, 'Guía Completa para Visitar la Cascada La Palmita', 'La Cascada La Palmita es una de las joyas naturales de Ortega. Con una caída de 30 metros rodeada de selva, es perfecta para senderismo y fotografía.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'guia-completa-para-visitar-la-cascada-la-palmita-69f0065e10acc', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(5, '5 Razones para Hacer Ecoturismo en el Tolima', 'El Tolima es uno de los destinos ecoturísticos más ricos de Colombia. Desde reservas naturales hasta petroglifos indígenas, la biodiversidad y el patrimonio cultural hacen de este departamento un paraíso para el viajero consciente.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', '5-razones-para-hacer-ecoturismo-en-el-tolima-69f0065e1226b', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(6, 'Gastronomía Tolimense: Platos que Debes Probar', 'El viudo de capaz, el tamal tolimense y la lechona son solo el comienzo. La cocina del Tolima es un viaje por sabores ancestrales que combinan maíz, plátano, yuca y carnes criollas en preparaciones únicas en Colombia.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'gastronomia-tolimense-platos-que-debes-probar-69f0065e13457', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(7, 'Cómo Llegar a Ortega desde Bogotá en Bus', 'Viajar de Bogotá a Ortega es más fácil de lo que crees. El trayecto tarda aproximadamente 4 horas en bus desde el Terminal de Transporte del Sur.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'como-llegar-a-ortega-desde-bogota-en-bus-69f0065e141d1', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(8, 'Los Mejores Hoteles Campestres de Ortega', 'Desde eco lodges hasta glamping bajo las estrellas, Ortega tiene opciones de alojamiento para todos los presupuestos.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'los-mejores-hoteles-campestres-de-ortega-69f0065e154bb', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(9, 'Petroglifos Pijao: Historia Milenaria en Piedra', 'La Piedra Pintada de Ortega es uno de los sitios arqueológicos más importantes del Tolima. Sus petroglifos, tallados por la cultura indígena Pijao hace más de 1000 años, son un testimonio fascinante de la historia precolombina.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'petroglifos-pijao-historia-milenaria-en-piedra-69f0065e1647a', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(10, 'Turismo de Aventura en el Río Saldaña', 'El río Saldaña ofrece experiencias únicas para los amantes de la aventura: rafting, kayak, pesca deportiva y baños en sus aguas cristalinas.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'turismo-de-aventura-en-el-rio-saldana-69f0065e1746d', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(11, 'Festival del Río: La Gran Fiesta de Ortega', 'Cada año, Ortega celebra el Festival del Río Saldaña con música folclórica, danzas tradicionales y gastronomía típica.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'festival-del-rio-la-gran-fiesta-de-ortega-69f0065e186f0', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(12, 'Avistamiento de Aves en la Reserva Natural Pijao', 'La Reserva Natural Pijao alberga más de 180 especies de aves en su bosque seco tropical.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'avistamiento-de-aves-en-la-reserva-natural-pijao-69f0065e1978f', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(13, 'Turismo Rural: Aprende a Cultivar en Ortega', 'Las fincas agroturísticas de Ortega te invitan a vivir la experiencia de cosechar mango, cacao y plátano junto a familias campesinas.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'turismo-rural-aprende-a-cultivar-en-ortega-69f0065e1bdbb', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(14, 'Qué Hacer en Ortega con Niños', 'Ortega es un destino ideal para familias con niños. Actividades como recorridos en finca, baños en río, observación de animales y talleres de artesanía hacen de cada visita una aventura educativa.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'que-hacer-en-ortega-con-ninos-69f0065e1d80b', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(15, 'Mirador El Cielo: 360° de Pura Naturaleza', 'Desde el Alto de La Cruz, el Mirador El Cielo ofrece una vista panorámica de 360° sobre el valle del río Saldaña y las montañas del Tolima.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'mirador-el-cielo-360-de-pura-naturaleza-69f0065e1ef9d', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(16, 'Viaje Sostenible: Cómo Ser un Turista Responsable', 'El turismo responsable es clave para preservar los destinos naturales del Tolima. Te damos consejos prácticos para reducir tu huella ambiental.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'viaje-sostenible-como-ser-un-turista-responsable-69f0065e20547', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(17, 'Los Termales de Ortega: Relajación Natural', 'Las aguas termales de La Sulfurosa en Ortega tienen propiedades medicinales reconocidas por la comunidad local.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'los-termales-de-ortega-relajacion-natural-69f0065e22b68', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(18, 'Artesanías Pijao: Arte que Cuenta Historias', 'Los artesanos de Ortega preservan las tradiciones de la cultura Pijao a través de tejidos, cerámicas y tallas en madera.', NULL, 'noticia', NULL, NULL, NULL, false, '2026-04-28 00:59:10', 'artesanias-pijao-arte-que-cuenta-historias-69f0065e2396b', '2026-04-28 00:59:10', '2026-04-28 00:59:10'),
(35, 'el cerro de los Abechucos', 'ES MUY BONITO', 'https://th.bing.com/th/id/OIP.AaGzAlj7P6XDEL6WmWIKaAHaFj?w=287&h=215&c=7&r=0&o=7&dpr=1.5&pid=1.7&rm=3', 'evento', 'Hotel El Paraíso S.A.S', 1, 12, false, '2026-04-28 11:44:22', 'el-cerro-de-los-abechucos-69f09d964a795', '2026-04-28 11:44:22', '2026-04-28 11:44:22')
